export default function Page() {
    const router = useRouter();
    const [selected, setSelected] = useState<number>(0);

    useEffect(() => {
        function handleKeydown(event: KeyboardEvent) {
            if (event.shiftKey || event.metaKey || event.ctrlKey || event.altKey) return;

            if (event.key === 'r') {
                router.push('/resume');

                return;
            }

            if (event.key === 't') {
                router.push('/tools');

                return;
            }

            if (event.key === 'd') {
                router.push('/docs');

                return;
            }

            if (event.key === 'c') {
                router.push('/config');

                return;
            }

            if (event.key === 'j') {
                setSelected((prev) => {
                    if (prev === options.length - 1) return prev;

                    return prev + 1;
                });

                return;
            }

            if (event.key === 'k') {
                setSelected((prev) => {
                    if (prev === 0) return prev;

                    return prev - 1;
                });

                return;
            }

            if (event.key === 'Enter') {
                router.push(options[selected].href);

                return;
            }
        }

        window.addEventListener('keydown', handleKeydown);

        return () => {
            window.removeEventListener('keydown', handleKeydown);
        };
    }, [selected]);

    return (
        <div className={styles.page}>
            <div className={styles.splash}>
                <div className={styles.ascii}>{ascii}</div>
                <div className={styles.options}>
                    {options.map(({ icon, label, href, cmd }, index) => {
                        return (
                            <Link key={index} href={href} className={styles.option}>
                                <span className={styles.label}>
                                    {icon}
                                    <span>
                                        <span
                                            className={`${styles.highlight} ${index === selected ? styles.selected : styles.normal}`}
                                        >
                                            {label[0]}
                                        </span>
                                        {label.slice(1)}
                                    </span>
                                </span>
                                <span className={styles.cmd}>{cmd}</span>
                            </Link>
                        );
                    })}
                </div>
                <div className={styles.footer}>
                    <Time />
                </div>
            </div>
        </div>
    );
}
